/**
 * Estrutura de dados bruta para auditoria e processamento posterior.
 * O conteúdo 'content' é imutável nesta fase.
 */
export interface RawDocument<T = any> {
  sourceName: string;
  fileType: FileType;
  content: T; // string, string[][] ou buffer
  timestamp: string;
  metadata: {
    size: number;
    encoding: string;
  };
}

import { FileType, RawDocument } from '../types/core-engine';

export abstract class BaseAdapter<T> {
  protected abstract fileType: FileType;

  /**
   * Realiza a leitura fiel do arquivo sem modificações.
   */
  abstract readRaw(file: File): Promise<RawDocument<T>>;

  protected createRawDocument(file: File, content: T): RawDocument<T> {
    return {
      sourceName: file.name,
      fileType: this.fileType,
      content,
      timestamp: new Date().toISOString(),
      metadata: {
        size: file.size,
        encoding: 'UTF-8'
      }
    };
  }
}

import { BaseAdapter } from './BaseAdapter';
import { FileType, RawDocument } from '../types/core-engine';

export class TextAdapter extends BaseAdapter<string> {
  protected fileType: FileType;

  constructor(type: FileType = FileType.TXT) {
    super();
    this.fileType = type;
  }

  async readRaw(file: File): Promise<RawDocument<string>> {
    const text = await file.text();
    return this.createRawDocument(file, text);
  }
}

import { BaseAdapter } from './BaseAdapter';
import { FileType, RawDocument } from '../types/core-engine';
import * as XLSX from 'xlsx';

export class ExcelAdapter extends BaseAdapter<string[][]> {
  protected fileType = FileType.XLSX;

  async readRaw(file: File): Promise<RawDocument<string[][]>> {
    const buffer = await file.arrayBuffer();
    const workbook = XLSX.read(new Uint8Array(buffer), { 
      type: 'array',
      cellDates: false, // Mantém datas como strings originais
      cellText: true,   // Prioriza o texto formatado da célula
      raw: false        // Garante que pegamos o que o usuário "vê"
    });

    const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
    const data = XLSX.utils.sheet_to_json(firstSheet, { 
      header: 1,
      defval: '' 
    }) as string[][];

    return this.createRawDocument(file, data);
  }
}

import { BaseAdapter } from './BaseAdapter';
import { FileType, RawDocument } from '../types/core-engine';

export class PDFAdapter extends BaseAdapter<string[]> {
  protected fileType = FileType.PDF;

  async readRaw(file: File): Promise<RawDocument<string[]>> {
    // Nota: pdfjsLib deve ser carregado via import map ou dinamicamente como no componente original
    const pdfjsLib = (window as any).pdfjsLib;
    if (!pdfjsLib) throw new Error("PDF Library not initialized");

    const buffer = await file.arrayBuffer();
    const loadingTask = pdfjsLib.getDocument(new Uint8Array(buffer));
    const pdf = await loadingTask.promise;

    let allLines: string[] = [];

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const items = textContent.items as any[];

      // Agrupamento RAW por coordenada Y para manter fidelidade de linha
      const lineMap: Map<number, any[]> = new Map();
      items.forEach(item => {
        const y = Math.round(item.transform[5]);
        if (!lineMap.has(y)) lineMap.set(y, []);
        lineMap.get(y)!.push(item);
      });

      const sortedY = Array.from(lineMap.keys()).sort((a, b) => b - a);
      sortedY.forEach(y => {
        const row = lineMap.get(y)!
          .sort((a, b) => a.transform[4] - b.transform[4])
          .map(item => item.str)
          .join(' ');

        if (row.trim()) allLines.push(row);
      });
    }

    return this.createRawDocument(file, allLines);
  }
}

