/**
 * Representação intermediária de uma transação.
 * Campos ainda são strings pois não passaram pela Normalização/Sanitização.
 */
export interface TransactionDraft {
  rawDate: string;
  rawDescription: string;
  rawAmount: string;
  sourceRowIndex: number;
  metadata: Record<string, any>;
}

import { RawDocument, TransactionDraft } from '../types/core-engine';

export abstract class BaseParser<T> {
  /**
   * Converte o conteúdo RAW em uma lista de rascunhos de transação.
   */
  abstract parse(doc: RawDocument<T>): TransactionDraft[];

  /**
   * Helper para validar se uma string tem potencial de ser um valor financeiro.
   */
  protected isLikelyAmount(val: string): boolean {
    if (!val) return false;
    const clean = val.replace(/[R$\s.]/g, '').replace(',', '.');
    return !isNaN(parseFloat(clean)) && /\d/.test(clean);
  }

  /**
   * Helper para validar se uma string tem potencial de ser uma data.
   */
  protected isLikelyDate(val: string): boolean {
    if (!val || val.length < 5) return false;
    return /(\d{2}[/-]\d{2}[/-]\d{2,4})|(\d{4}-\d{2}-\d{2})/.test(val);
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';

export class CSVParser extends BaseParser<string[][]> {

  parse(doc: RawDocument<string[][]>): TransactionDraft[] {
    const rows = doc.content;
    if (rows.length === 0) return [];

    // Identifica dinamicamente os índices das colunas
    const indices = this.detectColumns(rows.slice(0, 10));
    const drafts: TransactionDraft[] = [];

    rows.forEach((row, index) => {
      const dateVal = row[indices.date];
      const amountVal = row[indices.amount];

      if (this.isLikelyDate(dateVal) && this.isLikelyAmount(amountVal)) {
        drafts.push({
          rawDate: dateVal,
          rawDescription: row[indices.description] || '',
          rawAmount: amountVal,
          sourceRowIndex: index,
          metadata: { originalLine: row.join(' | ') }
        });
      }
    });

    return drafts;
  }

  private detectColumns(sample: string[][]): { date: number, amount: number, description: number } {
    let dateIdx = 0, amountIdx = 2, descIdx = 1;

    // Heurística baseada em padrões de dados nas primeiras linhas
    for (let i = 0; i < sample[0].length; i++) {
      const cell = String(sample.find(r => r[i])?.[i] || '');
      if (this.isLikelyDate(cell)) dateIdx = i;
      else if (this.isLikelyAmount(cell)) amountIdx = i;
      else if (cell.length > 5) descIdx = i;
    }

    return { date: dateIdx, amount: amountIdx, description: descIdx };
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';

export class OFXParser extends BaseParser<string> {

  parse(doc: RawDocument<string>): TransactionDraft[] {
    const drafts: TransactionDraft[] = [];
    const transactions = doc.content.split('<STMTTRN>');

    // Remove o header (primeiro elemento antes do primeiro <STMTTRN>)
    transactions.shift();

    transactions.forEach((tx, index) => {
      const date = this.getTagValue(tx, 'DTPOSTED');
      const amount = this.getTagValue(tx, 'TRNAMT');
      const memo = this.getTagValue(tx, 'MEMO') || this.getTagValue(tx, 'NAME');

      if (date && amount) {
        drafts.push({
          rawDate: date,
          rawDescription: memo || 'Sem descrição',
          rawAmount: amount,
          sourceRowIndex: index,
          metadata: { type: this.getTagValue(tx, 'TRNTYPE') }
        });
      }
    });

    return drafts;
  }

  private getTagValue(xml: string, tag: string): string {
    const regex = new RegExp(`<${tag}>([^<]+)`, 'i');
    const match = xml.match(regex);
    return match ? match[1].trim() : '';
  }
}

import { RawDocument } from '../types/core-engine';

/**
 * Especialista em inteligência cronológica.
 * Identifica a coluna de data por amostragem e corrige datas incompletas.
 */
export class DateResolver {
  private static DATE_PATTERNS = [
    /(\d{2})[/-](\d{2})[/-](\d{4})/, // DD/MM/YYYY ou DD-MM-YYYY
    /(\d{4})-(\d{2})-(\d{2})/,       // YYYY-MM-DD
    /(\d{2})[/-](\d{2})/             // DD/MM ou DD-MM (Incompleta)
  ];

  /**
   * Identifica qual índice de coluna na matriz representa a Data.
   */
  static identifyDateColumn(rows: string[][]): number {
    const sample = rows.slice(0, 50);
    const scores = new Array(rows[0]?.length || 0).fill(0);

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (this.isValidDatePattern(cell)) {
          scores[index]++;
        }
      });
    });

    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : 0;
  }

  /**
   * Extrai o ano de uma data completa encontrada em qualquer lugar do cabeçalho.
   */
  static discoverAnchorYear(content: any): number {
    const textToScan = typeof content === 'string' 
      ? content.substring(0, 2000) 
      : JSON.stringify(content).substring(0, 2000);

    // Procura por YYYY em formatos comuns
    const fullDateMatch = textToScan.match(/(\d{2}[/-]\d{2}[/-](\d{4}))|((\d{4})-\d{2}-\d{2})/);

    if (fullDateMatch) {
      // Pega o grupo que capturou os 4 dígitos do ano
      return parseInt(fullDateMatch[2] || fullDateMatch[4]);
    }

    return new Date().getFullYear(); // Fallback para o ano atual
  }

  /**
   * Resolve uma string de data bruta para o formato ISO YYYY-MM-DD.
   * Se a data for parcial, usa o anchorYear.
   */
  static resolveToISO(rawDate: string, anchorYear: number): string {
    const clean = rawDate.trim().replace(/-/g, '/');
    const parts = clean.split('/');

    let day = '', month = '', year = anchorYear.toString();

    if (parts.length >= 2) {
      // Caso DD/MM/YYYY ou DD/MM
      if (parts[0].length === 2) {
        day = parts[0].padStart(2, '0');
        month = parts[1].padStart(2, '0');
        if (parts[2] && parts[2].length === 4) year = parts[2];
        else if (parts[2] && parts[2].length === 2) year = '20' + parts[2];
      } 
      // Caso YYYY/MM/DD
      else if (parts[0].length === 4) {
        year = parts[0];
        month = parts[1].padStart(2, '0');
        day = parts[2].padStart(2, '0');
      }
    }

    // Validação básica de saída
    if (!day || !month || parseInt(month) > 12 || parseInt(day) > 31) {
      return ''; // Data inválida
    }

    return `${year}-${month}-${day}`;
  }

  private static isValidDatePattern(val: string): boolean {
    if (!val || val.length < 4) return false;
    return this.DATE_PATTERNS.some(regex => regex.test(val));
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';
import { DateResolver } from '../processors/DateResolver';

export class CSVParser extends BaseParser<string[][]> {

  parse(doc: RawDocument<string[][]>): TransactionDraft[] {
    const rows = doc.content;
    if (rows.length === 0) return [];

    const anchorYear = DateResolver.discoverAnchorYear(doc.content);
    const dateIdx = DateResolver.identifyDateColumn(rows);

    // Otimização: reutiliza detecção de colunas para outros campos
    const otherIndices = this.detectOtherColumns(rows.slice(0, 10), dateIdx);

    const drafts: TransactionDraft[] = [];

    rows.forEach((row, index) => {
      const rawDate = row[dateIdx];
      const isoDate = DateResolver.resolveToISO(rawDate || '', anchorYear);
      const amountVal = row[otherIndices.amount];

      if (isoDate && this.isLikelyAmount(amountVal)) {
        drafts.push({
          rawDate: isoDate, // Agora já normalizada
          rawDescription: row[otherIndices.description] || '',
          rawAmount: amountVal,
          sourceRowIndex: index,
          metadata: { 
            originalDate: rawDate,
            anchorYearUsed: anchorYear 
          }
        });
      }
    });

    return drafts;
  }

  private detectOtherColumns(sample: string[][], skipIdx: number): { amount: number, description: number } {
    let amountIdx = -1, descIdx = -1;

    for (let i = 0; i < sample[0].length; i++) {
      if (i === skipIdx) continue;

      const cell = String(sample.find(r => r[i])?.[i] || '');
      if (this.isLikelyAmount(cell) && amountIdx === -1) amountIdx = i;
      else if (cell.length > 5 && descIdx === -1) descIdx = i;
    }

    return { 
      amount: amountIdx === -1 ? 2 : amountIdx, 
      description: descIdx === -1 ? 1 : descIdx 
    };
  }
}

/**
 * Especialista em processamento de nomes e descrições textuais.
 * Focado em separar o nome da pessoa do ruído bancário.
 */
export class NameResolver {
  private static BANK_NOISE = [
    /\bPIX\b/gi, /\bTED\b/gi, /\bDOC\b/gi, /\bTRANSF\b/gi, /\bTRANSFERENCIA\b/gi,
    /\bRECEBIDO\b/gi, /\bENVIADO\b/gi, /\bPAGTO\b/gi, /\bPAGAMENTO\b/gi,
    /\bCONTA\b/gi, /\bCORRENTE\b/gi, /\bPOUPANCA\b/gi, /\bBANCO\b/gi
  ];

  /**
   * Identifica a coluna que provavelmente contém os nomes/descrições.
   */
  static identifyNameColumn(rows: string[][], excludedIndices: number[]): number {
    const sample = rows.slice(0, 50);
    const scores = new Array(rows[0]?.length || 0).fill(0);

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excludedIndices.includes(index)) return;

        const text = String(cell || '');
        if (text.length < 3) return;

        // Critério 1: Mais letras que números
        const letters = text.replace(/[^a-zA-Z]/g, '').length;
        const digits = text.replace(/[^0-9]/g, '').length;

        if (letters > digits) {
          scores[index] += 2;
        }

        // Critério 2: Múltiplas palavras (característica de nomes)
        if (text.trim().split(/\s+/).length >= 2) {
          scores[index] += 1;
        }
      });
    });

    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : -1;
  }

  /**
   * Limpa o ruído de uma string de nome, mantendo apenas as palavras válidas.
   */
  static clean(rawName: string): string {
    if (!rawName) return '';

    let cleaned = rawName;

    // 1. Remove padrões de ruído bancário conhecidos
    this.BANK_NOISE.forEach(pattern => {
      cleaned = cleaned.replace(pattern, '');
    });

    // 2. Remove números soltos (agências, contas, IDs de transação)
    // Mas mantém números se estiverem colados em letras (raro em nomes)
    cleaned = cleaned.replace(/(^|\s)\d+(\s|$)/g, ' ');

    // 3. Remove caracteres especiais
    cleaned = cleaned.replace(/[*\-_.,;:/\\|()]/g, ' ');

    // 4. Colapsa espaços
    return cleaned.replace(/\s+/g, ' ').trim();
  }

  /**
   * Normaliza a string para comparação (sem acentos, minúscula).
   */
  static normalize(text: string): string {
    return text
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '') // Remove acentos
      .trim();
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';
import { DateResolver } from '../processors/DateResolver';
import { NameResolver } from '../processors/NameResolver';

export class CSVParser extends BaseParser<string[][]> {

  parse(doc: RawDocument<string[][]>): TransactionDraft[] {
    const rows = doc.content;
    if (rows.length === 0) return [];

    // 1. Fase de Descoberta Topológica
    const anchorYear = DateResolver.discoverAnchorYear(doc.content);
    const dateIdx = DateResolver.identifyDateColumn(rows);

    // Identifica coluna de valor (excluindo a de data)
    const amountIdx = this.identifyAmountColumn(rows, [dateIdx]);

    // Identifica coluna de nome (excluindo data e valor)
    const nameIdx = NameResolver.identifyNameColumn(rows, [dateIdx, amountIdx]);

    const drafts: TransactionDraft[] = [];

    // 2. Fase de Extração e Limpeza Inicial
    rows.forEach((row, index) => {
      const rawDate = row[dateIdx];
      const rawName = row[nameIdx];
      const rawAmount = row[amountIdx];

      const isoDate = DateResolver.resolveToISO(rawDate || '', anchorYear);

      if (isoDate && this.isLikelyAmount(rawAmount)) {
        // Aplica a primeira camada de limpeza no nome
        const cleanedName = NameResolver.clean(rawName || '');

        drafts.push({
          rawDate: isoDate,
          rawDescription: cleanedName, // Já entregamos a descrição limpa para o pipeline
          rawAmount: rawAmount,
          sourceRowIndex: index,
          metadata: { 
            originalName: rawName,
            originalDate: rawDate,
            anchorYearUsed: anchorYear 
          }
        });
      }
    });

    return drafts;
  }

  private identifyAmountColumn(rows: string[][], excluded: number[]): number {
    const sample = rows.slice(0, 50);
    const scores = new Array(rows[0]?.length || 0).fill(0);

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excluded.includes(index)) return;
        if (this.isLikelyAmount(cell)) {
          scores[index]++;
        }
      });
    });

    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : (excluded.includes(2) ? 1 : 2);
  }
}

/**
 * Especialista em processamento de valores financeiros.
 * Identifica a coluna correta por magnitude e limpa ruídos alfanuméricos.
 */
export class AmountResolver {
  /**
   * Identifica a coluna de valor correta entre múltiplas candidatas.
   * Se houver mais de uma, escolhe a de menor magnitude (Transação vs Saldo).
   */
  static identifyAmountColumn(rows: string[][], excludedIndices: number[]): number {
    const sample = rows.slice(0, 50);
    const candidateScores = new Map<number, { count: number, totalMagnitude: number }>();

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excludedIndices.includes(index)) return;

        const val = this.simpleParse(cell);
        if (val !== null) {
          const stats = candidateScores.get(index) || { count: 0, totalMagnitude: 0 };
          stats.count++;
          stats.totalMagnitude += Math.abs(val);
          candidateScores.set(index, stats);
        }
      });
    });

    // Filtra apenas colunas que aparecem como valor em pelo menos 30% da amostra
    const validCandidates = Array.from(candidateScores.entries())
      .filter(([_, stats]) => stats.count > (sample.length * 0.3));

    if (validCandidates.length === 0) return -1;

    // Se houver mais de uma, a de MENOR magnitude média é a transação
    validCandidates.sort((a, b) => {
      const avgA = a[1].totalMagnitude / a[1].count;
      const avgB = b[1].totalMagnitude / b[1].count;
      return avgA - avgB;
    });

    return validCandidates[0][0];
  }

  /**
   * Limpa letras e símbolos, padronizando para string numérica pura.
   * Ex: "R$ 1.250,50" -> "1250.50"
   */
  static clean(rawAmount: string): string {
    if (!rawAmount) return "0.00";

    // 1. Detecta sinal negativo (hífen ou parênteses)
    const isNegative = rawAmount.includes('-') || (rawAmount.includes('(') && rawAmount.includes(')'));

    // 2. Remove tudo que não seja dígito, vírgula ou ponto
    let cleaned = rawAmount.replace(/[^-0-9.,]/g, '');

    // 3. Trata separadores decimais (Padrão BR: 1.000,50 -> 1000.50)
    const hasComma = cleaned.includes(',');
    const hasDot = cleaned.includes('.');

    if (hasComma && hasDot) {
      // Caso clássico: 1.234,56
      cleaned = cleaned.replace(/\./g, '').replace(',', '.');
    } else if (hasComma) {
      // Caso: 1234,56
      cleaned = cleaned.replace(',', '.');
    } else if (hasDot) {
      // Caso: 1234.56 ou 1.234 (Ambiguidade)
      const parts = cleaned.split('.');
      if (parts[parts.length - 1].length === 3 && cleaned.length > 4) {
        // Provavelmente milhar: 1.000 -> 1000.00
        cleaned = cleaned.replace(/\./g, '');
      }
    }

    const numericValue = parseFloat(cleaned);
    if (isNaN(numericValue)) return "0.00";

    const finalValue = isNegative ? -Math.abs(numericValue) : numericValue;
    return finalValue.toFixed(2);
  }

  /**
   * Versão simplificada para detecção de coluna (sem cleaning pesado).
   */
  private static simpleParse(val: string): number | null {
    if (!val || val.length < 1) return null;
    const clean = val.replace(/[R$\s]/g, '').replace(',', '.');
    const parsed = parseFloat(clean);
    return isNaN(parsed) ? null : parsed;
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';
import { DateResolver } from '../processors/DateResolver';
import { NameResolver } from '../processors/NameResolver';
import { AmountResolver } from '../processors/AmountResolver';

export class CSVParser extends BaseParser<string[][]> {

  parse(doc: RawDocument<string[][]>): TransactionDraft[] {
    const rows = doc.content;
    if (rows.length === 0) return [];

    // 1. Fase de Descoberta Topológica (Inteligência de Coluna)
    const anchorYear = DateResolver.discoverAnchorYear(doc.content);
    const dateIdx = DateResolver.identifyDateColumn(rows);

    // Identifica coluna de valor (excluindo a de data já encontrada)
    const amountIdx = AmountResolver.identifyAmountColumn(rows, [dateIdx]);

    // Identifica coluna de nome (excluindo data e valor)
    const nameIdx = NameResolver.identifyNameColumn(rows, [dateIdx, amountIdx]);

    const drafts: TransactionDraft[] = [];

    // 2. Fase de Extração e Normalização Intermediária
    rows.forEach((row, index) => {
      const rawDate = row[dateIdx];
      const rawName = row[nameIdx];
      const rawAmount = row[amountIdx];

      const isoDate = DateResolver.resolveToISO(rawDate || '', anchorYear);

      if (isoDate && rawAmount && rawAmount.trim() !== '') {
        // Aplica as limpezas especialistas
        const cleanedName = NameResolver.clean(rawName || '');
        const standardizedAmount = AmountResolver.clean(rawAmount);

        // Só adiciona se o valor for diferente de zero (ignora linhas vazias ou de saldo zerado)
        if (standardizedAmount !== "0.00") {
          drafts.push({
            rawDate: isoDate,
            rawDescription: cleanedName,
            rawAmount: standardizedAmount,
            sourceRowIndex: index,
            metadata: { 
              originalName: rawName,
              originalDate: rawDate,
              originalAmount: rawAmount,
              anchorYearUsed: anchorYear 
            }
          });
        }
      }
    });

    return drafts;
  }
}

/**
 * Especialista em processamento de nomes e descrições textuais.
 * Focado em separar o nome da pessoa do ruído bancário.
 */
export class NameResolver {
  private static BANK_NOISE = [
    /\bPIX\b/gi, /\bTED\b/gi, /\bDOC\b/gi, /\bTRANSF\b/gi, /\bTRANSFERENCIA\b/gi,
    /\bRECEBIDO\b/gi, /\bENVIADO\b/gi, /\bPAGTO\b/gi, /\bPAGAMENTO\b/gi,
    /\bCONTA\b/gi, /\bCORRENTE\b/gi, /\bPOUPANCA\b/gi, /\bBANCO\b/gi
  ];

  private static CONTROL_KEYWORDS = [
    'SALDO', 'TOTAL', 'SOMATORIO', 'RESUMO', 'FECHAMENTO', 
    'ACUMULADO', 'DISPONIVEL', 'APLICACAO', 'RESGATE'
  ];

  /**
   * Identifica a coluna que provavelmente contém os nomes/descrições.
   */
  static identifyNameColumn(rows: string[][], excludedIndices: number[]): number {
    const sample = rows.slice(0, 50);
    const scores = new Array(rows[0]?.length || 0).fill(0);

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excludedIndices.includes(index)) return;

        const text = String(cell || '');
        if (text.length < 3) return;

        const letters = text.replace(/[^a-zA-Z]/g, '').length;
        const digits = text.replace(/[^0-9]/g, '').length;

        if (letters > digits) {
          scores[index] += 2;
        }

        if (text.trim().split(/\s+/).length >= 2) {
          scores[index] += 1;
        }
      });
    });

    const maxScore = Math.max(...scores);
    return maxScore > 0 ? scores.indexOf(maxScore) : -1;
  }

  /**
   * Verifica se a linha é apenas um metadado bancário (Saldo/Total).
   */
  static isControlRow(text: string): boolean {
    if (!text) return false;
    const upper = text.toUpperCase();
    return this.CONTROL_KEYWORDS.some(keyword => upper.includes(keyword));
  }

  /**
   * Limpa o ruído de uma string de nome, mantendo apenas as palavras válidas.
   */
  static clean(rawName: string): string {
    if (!rawName) return '';

    let cleaned = rawName;

    this.BANK_NOISE.forEach(pattern => {
      cleaned = cleaned.replace(pattern, '');
    });

    cleaned = cleaned.replace(/(^|\s)\d+(\s|$)/g, ' ');
    cleaned = cleaned.replace(/[*\-_.,;:/\\|()]/g, ' ');

    return cleaned.replace(/\s+/g, ' ').trim();
  }

  /**
   * Normaliza a string para comparação (sem acentos, minúscula).
   */
  static normalize(text: string): string {
    return text
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .trim();
  }
}

import { BaseParser } from './BaseParser';
import { RawDocument, TransactionDraft } from '../types/core-engine';
import { DateResolver } from '../processors/DateResolver';
import { NameResolver } from '../processors/NameResolver';
import { AmountResolver } from '../processors/AmountResolver';

export class CSVParser extends BaseParser<string[][]> {

  parse(doc: RawDocument<string[][]>): TransactionDraft[] {
    const rows = doc.content;
    if (rows.length === 0) return [];

    // 1. Fase de Descoberta Topológica
    const anchorYear = DateResolver.discoverAnchorYear(doc.content);
    const dateIdx = DateResolver.identifyDateColumn(rows);
    const amountIdx = AmountResolver.identifyAmountColumn(rows, [dateIdx]);
    const nameIdx = NameResolver.identifyNameColumn(rows, [dateIdx, amountIdx]);

    const drafts: TransactionDraft[] = [];

    // 2. Fase de Extração com Filtro de Integridade
    rows.forEach((row, index) => {
      const rawDate = row[dateIdx];
      const rawName = row[nameIdx] || '';
      const rawAmount = row[amountIdx] || '';

      // Regra: Descarta linhas que contenham palavras de controle (SALDO, TOTAL, etc)
      if (NameResolver.isControlRow(rawName)) {
        return;
      }

      const isoDate = DateResolver.resolveToISO(rawDate || '', anchorYear);

      // Regra: Só processa se houver data e valor válidos
      if (isoDate && rawAmount.trim() !== '') {
        const standardizedAmount = AmountResolver.clean(rawAmount);

        // Regra: Descarta valores zerados (frequentemente linhas de separação ou saldos vazios)
        if (standardizedAmount !== "0.00") {
          const cleanedName = NameResolver.clean(rawName);

          drafts.push({
            rawDate: isoDate,
            rawDescription: cleanedName,
            rawAmount: standardizedAmount, // Se for negativo, já vem com "-"
            sourceRowIndex: index,
            metadata: { 
              isExpense: parseFloat(standardizedAmount) < 0,
              originalName: rawName,
              originalAmount: rawAmount
            }
          });
        }
      }
    });

    return drafts;
  }
}

