/**
 * Árbitro final de integridade.
 * Garante que apenas dados financeiros reais e completos progridam.
 */
export class RowValidator {

  /**
   * Valida se uma transação possui todos os requisitos para ser processada.
   * @param isoDate Data já normalizada pelo DateResolver
   * @param rawDescription Descrição bruta da linha
   * @param standardizedAmount Valor já limpo pelo AmountResolver
   */
  static isValid(isoDate: string, rawDescription: string, standardizedAmount: string): boolean {
    // 1. Requisito: Data válida e completa
    if (!isoDate || isoDate.length !== 10) {
      return false;
    }

    // 2. Requisito: Descrição não vazia e não sendo linha de controle (Saldo/Total)
    if (!rawDescription || rawDescription.trim().length < 2) {
      return false;
    }

    if (NameResolver.isControlRow(rawDescription)) {
      return false;
    }

    // 3. Requisito: Valor numérico real e diferente de zero
    const numericValue = parseFloat(standardizedAmount);
    if (isNaN(numericValue) || numericValue === 0) {
      return false;
    }

    return true;
  }
}

