/**
 * Representação intermediária de uma transação.
 * Campos ainda são strings pois não passaram pela Normalização/Sanitização.
 */
export interface TransactionDraft {
  rawDate: string;
  rawDescription: string;
  rawAmount: string;
  sourceRowIndex: number;
  metadata: Record<string, any>;
}

/**
 * Resultado FINAL e IMUTÁVEL do motor de processamento.
 * Exatamente 3 colunas conforme regra de negócio.
 */
export interface NormalizedTransaction {
  data: string;  // YYYY-MM-DD
  nome: string;  // Descrição Limpa
  valor: number; // Float 64
}

import { TransactionDraft, NormalizedTransaction } from '../types/core-engine';

/**
 * Consolidador Final do Core Engine.
 * Transforma rascunhos em registros financeiros tipados e padronizados.
 */
export class Normalizer {

  /**
   * Converte uma lista de rascunhos na estrutura final de 3 colunas.
   */
  static normalize(drafts: TransactionDraft[]): NormalizedTransaction[] {
    return drafts
      .map(draft => this.toNormalized(draft))
      .filter((tx): tx is NormalizedTransaction => tx !== null);
  }

  /**
   * Mapeia um rascunho individual para o contrato final.
   */
  private static toNormalized(draft: TransactionDraft): NormalizedTransaction | null {
    try {
      const valorNumerico = parseFloat(draft.rawAmount);

      // Validação de segurança final
      if (isNaN(valorNumerico)) return null;

      // Retorna EXATAMENTE as 3 colunas solicitadas
      return {
        data: draft.rawDate,
        nome: draft.rawDescription,
        valor: valorNumerico
      };
    } catch (e) {
      console.error("Falha na normalização final do registro", e);
      return null;
    }
  }
}

import { FileProbe } from './Probe';
import { FileType, NormalizedTransaction } from '../types/core-engine';
import { ExcelAdapter } from '../adapters/ExcelAdapter';
import { CSVParser } from '../parsers/CSVParser';
import { Normalizer } from './Normalizer';

/**
 * Cérebro do Core Engine v3.
 * Orquestra o fluxo de dados do arquivo bruto até a saída normalizada.
 */
export class Orchestrator {

  /**
   * Processa um arquivo financeiro e retorna dados em 3 colunas.
   */
  static async processFile(file: File): Promise<NormalizedTransaction[]> {
    // 1. Identificação (Probe)
    const probe = await FileProbe.identify(file);

    // 2. Leitura (Adapters) - Exemplo com CSV/Excel
    // Nota: Em uma implementação completa, haveria um Factory de Adapters aqui
    if (probe.type === FileType.XLSX || probe.type === FileType.CSV) {
      const adapter = new ExcelAdapter();
      const rawDoc = await adapter.readRaw(file);

      // 3. Extração (Parsers)
      const parser = new CSVParser();
      const drafts = parser.parse(rawDoc);

      // 4. Consolidação Final (Normalizer)
      return Normalizer.normalize(drafts);
    }

    throw new Error(`Tipo de arquivo ${probe.type} não suportado para processamento direto.`);
  }
}

