        expect(AmountResolver.clean('1.234,56')).toBe('1234.56');
    });

    it('Deve preservar sinal negativo em diferentes formatos', () => {
        expect(AmountResolver.clean('-150,00')).toBe('-150.00');
        expect(AmountResolver.clean('(150,00)')).toBe('-150.00');
    });

    it('Deve ignorar letras e R$ no valor', () => {
        expect(AmountResolver.clean('VALOR R$ 10,50')).toBe('10.50');
    });
});

describe('Core Engine: Normalização Final', () => {
    it('Deve garantir exatamente 3 colunas e tipos corretos', () => {
        const mockDraft = {
            rawDate: '2024-05-20',
            rawDescription: 'TESTE',
            rawAmount: '100.50',
            sourceRowIndex: 0,
            metadata: {}
        };
        const normalized = Normalizer.normalize([mockDraft])[0];

        expect(Object.keys(normalized).length).toBe(3);
        expect(typeof normalized.valor).toBe('number');
        expect(normalized.data).toBe('2024-05-20');
    });
});

